<?php\n\nclass FriendRequest {\n    private $db;\n    private $table = 'friend_requests';\n\n    public function __construct($db) {\n        $this->db = $db;\n    }\n\n    // Send friend request\n    public function sendRequest($sender_id, $receiver_id) {\n        if ($sender_id == $receiver_id) {\n            return false;\n        }\n\n        // Check if already sent\n        if ($this->requestExists($sender_id, $receiver_id)) {\n            return false;\n        }\n\n        // Check if already friends\n        if ($this->areFriends($sender_id, $receiver_id)) {\n            return false;\n        }\n\n        $query = 'INSERT INTO ' . $this->table . '\n                  (sender_id, receiver_id, status, created_at)\n                  VALUES\n                  (:sender_id, :receiver_id, \"pending\", NOW())';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':sender_id', $sender_id);\n        $stmt->bindParam(':receiver_id', $receiver_id);\n\n        return $stmt->execute();\n    }\n\n    // Accept friend request\n    public function acceptRequest($request_id, $receiver_id) {\n        // Update request status\n        $query = 'UPDATE ' . $this->table . '\n                  SET status = \"accepted\", updated_at = NOW()\n                  WHERE id = :id AND receiver_id = :receiver_id';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':id', $request_id);\n        $stmt->bindParam(':receiver_id', $receiver_id);\n\n        if ($stmt->execute()) {\n            // Get sender_id to create friendship\n            $query = 'SELECT sender_id FROM ' . $this->table . ' WHERE id = :id';\n            $stmt = $this->db->prepare($query);\n            $stmt->bindParam(':id', $request_id);\n            $stmt->execute();\n            $result = $stmt->fetch(PDO::FETCH_ASSOC);\n\n            if ($result) {\n                // Create friendship\n                $this->createFriendship($result['sender_id'], $receiver_id);\n                return true;\n            }\n        }\n        return false;\n    }\n\n    // Reject friend request\n    public function rejectRequest($request_id, $receiver_id) {\n        $query = 'UPDATE ' . $this->table . '\n                  SET status = \"rejected\", updated_at = NOW()\n                  WHERE id = :id AND receiver_id = :receiver_id';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':id', $request_id);\n        $stmt->bindParam(':receiver_id', $receiver_id);\n\n        return $stmt->execute();\n    }\n\n    // Delete friend request (sender can delete)\n    public function deleteRequest($request_id, $sender_id) {\n        $query = 'DELETE FROM ' . $this->table . '\n                  WHERE id = :id AND sender_id = :sender_id AND status = \"pending\"';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':id', $request_id);\n        $stmt->bindParam(':sender_id', $sender_id);\n\n        return $stmt->execute();\n    }\n\n    // Get pending requests for user\n    public function getPendingRequests($user_id) {\n        $query = 'SELECT fr.id, fr.sender_id, u.username, u.full_name, u.profile_pic, fr.created_at\n                  FROM ' . $this->table . ' fr\n                  JOIN users u ON fr.sender_id = u.id\n                  WHERE fr.receiver_id = :user_id AND fr.status = \"pending\"\n                  ORDER BY fr.created_at DESC';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id', $user_id);\n        $stmt->execute();\n\n        return $stmt->fetchAll(PDO::FETCH_ASSOC);\n    }\n\n    // Get sent requests\n    public function getSentRequests($user_id) {\n        $query = 'SELECT fr.id, fr.receiver_id, u.username, u.full_name, u.profile_pic, fr.created_at\n                  FROM ' . $this->table . ' fr\n                  JOIN users u ON fr.receiver_id = u.id\n                  WHERE fr.sender_id = :user_id AND fr.status = \"pending\"\n                  ORDER BY fr.created_at DESC';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id', $user_id);\n        $stmt->execute();\n\n        return $stmt->fetchAll(PDO::FETCH_ASSOC);\n    }\n\n    // Check if request exists\n    public function requestExists($sender_id, $receiver_id) {\n        $query = 'SELECT id FROM ' . $this->table . '\n                  WHERE (sender_id = :sender_id AND receiver_id = :receiver_id)\n                  OR (sender_id = :receiver_id AND receiver_id = :sender_id)\n                  AND status = \"pending\"';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':sender_id', $sender_id);\n        $stmt->bindParam(':receiver_id', $receiver_id);\n        $stmt->execute();\n\n        return $stmt->rowCount() > 0;\n    }\n\n    // Check if friends\n    public function areFriends($user_id1, $user_id2) {\n        $query = 'SELECT id FROM friends\n                  WHERE (user_id_1 = :user_id1 AND user_id_2 = :user_id2)\n                  OR (user_id_1 = :user_id2 AND user_id_2 = :user_id1)';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id1', $user_id1);\n        $stmt->bindParam(':user_id2', $user_id2);\n        $stmt->execute();\n\n        return $stmt->rowCount() > 0;\n    }\n\n    // Create friendship\n    private function createFriendship($user_id1, $user_id2) {\n        $query = 'INSERT INTO friends (user_id_1, user_id_2, created_at)\n                  VALUES (:user_id1, :user_id2, NOW())';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id1', $user_id1);\n        $stmt->bindParam(':user_id2', $user_id2);\n\n        return $stmt->execute();\n    }\n\n    // Remove friendship\n    public function removeFriend($user_id1, $user_id2) {\n        $query = 'DELETE FROM friends\n                  WHERE (user_id_1 = :user_id1 AND user_id_2 = :user_id2)\n                  OR (user_id_1 = :user_id2 AND user_id_2 = :user_id1)';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id1', $user_id1);\n        $stmt->bindParam(':user_id2', $user_id2);\n\n        return $stmt->execute();\n    }\n\n    // Get user friends\n    public function getUserFriends($user_id) {\n        $query = 'SELECT u.id, u.username, u.full_name, u.profile_pic\n                  FROM users u\n                  JOIN friends f ON (u.id = f.user_id_1 OR u.id = f.user_id_2)\n                  WHERE (f.user_id_1 = :user_id OR f.user_id_2 = :user_id)\n                  AND u.id != :user_id';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id', $user_id);\n        $stmt->execute();\n\n        return $stmt->fetchAll(PDO::FETCH_ASSOC);\n    }\n\n    // Get friends count\n    public function getFriendsCount($user_id) {\n        $query = 'SELECT COUNT(*) as count FROM friends\n                  WHERE user_id_1 = :user_id OR user_id_2 = :user_id';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id', $user_id);\n        $stmt->execute();\n\n        $result = $stmt->fetch(PDO::FETCH_ASSOC);\n        return $result['count'];\n    }\n}\n\n?>"